import React from 'react';
import { useEffect } from 'react';

import Aos from 'aos';
import 'aos/dist/aos.css';

import Main from '../components/Main';
import Item from '../components/Item';

import '../assets/styles/HomePage.css';

import google from '../assets/static/google.png';
import brand from '../assets/static/brand.png';
import platziVideo from '../assets/static/platziVideo.png';
import rickAndMorty from '../assets/static/rickAndMorty.png';

function HomePage() {
  useEffect(() => {
    Aos.init({ duration: 1000 });
  }, []);

  const itemContent = [
    {
      id: 0,
      image: rickAndMorty,
      text: 'Replica de The Rick and Morty API',
      subtitle: 'React.js',
      url: 'https://guidofabiancabrera.github.io/rickandmortyapi/#/',
    },
    {
      id: 2,
      image: platziVideo,
      text: 'Platzi - Video',
      subtitle: 'Html - Css - Bootstrap',
      url: 'https://guidofabiancabrera.github.io/platzivideo',
    },
    {
      id: 3,
      image: google,
      text: 'Replica de Google',
      subtitle: 'Html - Css',
      url: 'https://guidofabiancabrera.github.io/google',
    },
    {
      id: 4,
      image: brand,
      text: 'Platzi - Brand',
      subtitle: 'Html - Css',
      url: 'https://guidofabiancabrera.github.io/brand',
    },
    {
      id: 5,
      image: null,
    },
    {
      id: 6,
      image: null,
    },
    {
      id: 7,
      image: null,
    },
    {
      id: 8,
      image: null,
    },
  ];

  return (
    <>
      <Main />
      <div className="Portfolio">
        <h3 className="py-5" data-aos="fade-right">
          Portafolio
        </h3>
        <div className="Item__container">
          {itemContent.map((item) => (
            <Item key={item.id} {...item} />
          ))}
        </div>
      </div>
    </>
  );
}

export default HomePage;
