import React from 'react';

import '../assets/styles/Item.css';

import code from '../assets/static/code.png';

const Item = ({ image, text, url, subtitle }) => (
  <a className="Item" href={url} target="_blank" rel="noopener noreferrer">
    <img className="Item__image" src={image ? image : code} alt={text} />
    <div className="overlay p-4">
      <h4 className="m-0 mb-2">{text}</h4>
      <h6>{subtitle}</h6>
    </div>
  </a>
);

export default Item;
